const OIL_NOTES = [
  'Sovereign Wealth Fund (SWF)',
  'Daimler-Benz',
  'Krupp',
];

function OFn({ n }) { return <ArtFn n={n} notes={OIL_NOTES} />; }

function EssayOilToNarrative() {
  return (
    <React.Fragment>
      <p className="essay-lede">
        در جهان امروز، فرهنگ و هنر دیگر تنها عرصهٔ ذوق و خلاقیت نیستند، بلکه به بخشی از رقابت قدرت و کسب ثروت در عصر جدید تبدیل شده‌اند. در خاورمیانهٔ امروز، کشورهایی که دیروز با نفت شناخته می‌شدند، اکنون با موزه‌ها، جشنواره‌ها، موسیقی، هنر معاصر و صنایع خلاق برای پرستیژ، جذب گردشگر و نفوذ فرهنگی رقابت می‌کنند. کشورها دریافته‌اند که در جهانی اشباع از تصویر و روایت، آن‌که داستان خود را روایت نکند، دیر یا زود در روایت دیگران حل می‌شود. در این میان، ایران با وجود سرمایهٔ تاریخی و هنری بی‌بدیل، فاقد ابزار نهادی لازم برای ورود حرفه‌ای به این میدان است.
      </p>
      <AP>دولت‌های منطقه معمولاً از طریق صندوق‌های سرمایه‌گذاری و صندوق‌های ثروت ملی<OFn n={1} />، فرهنگ و هنر را برای سه هدف مشخص به‌کار می‌گیرند. نخست، توانمندسازی هنر داخلی؛ یعنی ایجاد زیرساخت تولید، توزیع و حضور جهانی برای هنرمندان، به‌گونه‌ای که هنر ملی بتواند از مرز حمایت‌های یارانه‌ای عبور کند و وارد بازار حرفه‌ای شود. دوم، ساخت و تقویت برند ملی؛ فرهنگ و هنر زبان غیررسمی دیپلماسی‌اند. موزه‌ها، جشنواره‌ها، فستیوال‌ها و رویدادهای هنری تصویری می‌سازند که مستقیماً بر گردشگری، سرمایه‌گذاری و اعتبار بین‌المللی اثر می‌گذارد. سوم، رقابت منطقه‌ای و جهانی؛ در خاورمیانهٔ امروز، کشورها به‌طور فعال برای تبدیل‌شدن به «مرکز فرهنگی» رقابت می‌کنند. این رقابت، دقیقاً مانند رقابت در انرژی یا فناوری، بدون سرمایه‌گذاری سازمان‌یافته ممکن نیست.</AP>
      <AP>این اهداف تصادفی نیستند. همان منطقی که امروز سرمایه‌های صندوق‌های دولتی خلیج فارس را به سمت هوش مصنوعی، انرژی، زیرساخت دیجیتال و فناوری‌های نو سوق داده، سال‌هاست در حوزهٔ فرهنگ و هنر نیز فعال شده است: سرمایه‌گذاری نه فقط برای سود مالی، بلکه برای تضمین سهم کشورها از قدرت آینده و ایجاد ادراک و تصویری مطلوب در سطح جهانی.</AP>

      <AH>از رقابت منطقه‌ای تا رقابت فرهنگی</AH>
      <AP>نگاهی به خاورمیانهٔ امروز نشان می‌دهد رقابت اصلی دیگر تنها بر سر امنیت یا انرژی نیست؛ بلکه رقابت بر سر «تصویر»، «برند» و «قدرت نرم» است. عربستان سعودی و امارات متحده عربی، با وجود ظاهر هم‌پیمانی، عملاً وارد یک رقابت ژئواکونومیک تمام‌عیار شده‌اند. این رقابت فقط به جذب سرمایه یا سیاست انرژی محدود نمی‌شود، بلکه در میزبانی نمایشگاه‌های جهانی، اجلاس‌ها، فستیوال‌های هنری، جشنواره‌های موسیقی و رویدادهای فرهنگی بزرگ نیز جریان دارد.</AP>
      <AP>دبی که به‌عنوان جامعه‌ای نسبتاً باز و جهان‌وطن شناخته می‌شود، توانسته است با جذب چهره‌های سرشناس، میزبان کنسرت‌ها و اجراهای هنری بین‌المللی باشد. با این حال، این امتیاز دیگر منحصر به امارات متحده عربی نیست. در دسامبر ۲۰۲۳، ریاض با موفقیت میزبان جشنوارهٔ موسیقی MDLBEAST Soundstorm شد؛ رویدادی که به‌عنوان بزرگ‌ترین جشنوارهٔ موسیقی خاورمیانه شناخته می‌شود. در مجموع، این اقدامات نشان‌دهندهٔ تلاش‌های آگاهانه و برنامه‌ریزی‌شدهٔ این دو کشور برای بازتعریف تصویر بین‌المللی خود و شکل‌دادن به برداشت‌های مثبت از جایگاه‌شان در عرصهٔ جهانی است.</AP>
      <AP>در همین راستا، «جشنوارهٔ نور ریاض» یکی از برنامه‌های «ریاض آرت» است که خود بخشی از چهار پروژهٔ بزرگ ریاض به‌شمار می‌آید که در ۱۹ مارس ۲۰۱۹ آغاز شدند؛ پروژه‌ای با هدف تبدیل پایتخت به یک نمایشگاه هنری باز که اصالت و مدرنیته را در هم می‌آمیزد و با اهداف چشم‌انداز سعودی ۲۰۳۰ در زمینهٔ تقویت فرهنگ و هنر و بهبود کیفیت زندگی هم‌راستا است. در نوامبر ۲۰۱۷ نیز دولت امارات، در چارچوب توافق سی‌ساله میان ابوظبی و پاریس، موزهٔ لوور ابوظبی را افتتاح کرد؛ موزه‌ای که ساخت آن ده سال به طول انجامید و امروز میزبان ۶۰۰ اثر دائمی و ۳۰۰ اثر امانی از فرانسه است.</AP>
      <AP>ریاض با میزبانی جشنواره‌های بزرگ موسیقی و هنر خاورمیانه نشان داده است که هنر و فرهنگ به بخشی از سیاست ملی و رقابت منطقه‌ای تبدیل شده‌اند. ابوظبی نیز سال‌هاست از طریق موزه‌ها، گالری‌ها، کنسرت‌ها و رویدادهای هنری، تصویری جهانی از خود می‌سازد که مستقیماً بر گردشگری، سرمایه‌گذاری و نفوذ فرهنگی اثر می‌گذارد. این‌ها هزینه‌های تزئینی نیستند؛ بلکه سرمایه‌گذاری‌های آگاهانه برای بازتعریف جایگاه این کشورها در افکار عمومی جهانی‌اند.</AP>

      <AH>ایران و تجربهٔ ناتمام صندوق‌های ثروت ملی</AH>
      <AP>نگاهی به تاریخ سرمایه‌گذاری‌های فرامرزی ایران در دهه‌های ۶۰ و ۷۰ میلادی، تصویری را پیش چشم می‌گذارد که حتی امروز نیز جسورانه به نظر می‌رسد؛ از خرید سهام «دایملر-بنز»<OFn n={2} /> و «کروپ»<OFn n={3} /> آلمان گرفته تا مشارکت در میدان گازی «روم» در قلب اسکاتلند، و حتی سرمایه‌گذاری در مزارع کشاورزی آیداهو و املاک و مستغلات ایالات متحدهٔ آمریکا. ایرانِ آن روزها فراتر از مرزهای جغرافیایی خود، به دنبال «امنیت آینده» بود.</AP>
      <AP>در تمامی این سرمایه‌گذاری‌ها یک نکته روشن است: ایران آن زمان به‌درستی دریافته بود که «درآمد نفت» باید به «دارایی پایدار» تبدیل شود. نگرانی از پایان‌پذیری نفت و لزوم آمادگی برای دوران پسا‌نفت، بارها در سخنان محمدرضا شاه پهلوی بازتاب یافته است. هرچند این نگاه از زمانهٔ خود جلوتر بود، اما فرصت آن را نیافت که به یک نهاد حرفه‌ای، شفاف و مستقل با استانداردهای بین‌المللی تبدیل شود و ثروت ملی را به‌صورت نسل‌به‌نسل بازتولید کند. انقلاب اسلامی ۵۷ بسیاری از این ظرفیت‌ها و ایده‌های آینده‌ساز را به خاکستری از شکست‌ها و هزینه‌ها بدل ساخت.</AP>
      <AP>در دوران جمهوری اسلامی نیز ایدهٔ صندوق توسعهٔ ملی مطرح شد، اما در عمل—و همچون بسیاری از سیاست‌های وام‌گرفته از گذشته—این صندوق بیشتر به ابزاری برای جبران کسری بودجه، مخارج ایدئولوژیک و حل مسائل کوتاه‌مدت تبدیل شد. نتیجه آن‌که امروز نه نقشی تثبیت‌کننده دارد، نه موتور توسعه است و نه شباهتی به صندوق‌های موفق منطقه‌ای و جهانی.</AP>

      <AH>ایران آینده، سرمایه‌گذاری و فرهنگ و هنر</AH>
      <AP>اگر بخواهیم صادق باشیم، ایجاد یک صندوق ثروت ملی با استانداردهای امروزی و تخصیص بخشی از سرمایه‌گذاری‌ها به فرهنگ و هنر—در راستای منافع ایران به‌مثابه یک دولت–ملت—تنها از دولتی ملی برمی‌آید؛ امری که تا اطلاع ثانوی ایران امروز از آن محروم است. با این حال، همان‌گونه که محمدرضا شاه پهلوی در یکی از آخرین مصاحبه‌های خود گفت: «یک وطن‌دوست همواره باید به فکر آینده باشد». امروز نیز همهٔ کسانی که دل در گرو بازپس‌گیری و بازسازی ایران آینده دارند، باید خود را برای لحظهٔ شکوفایی آماده سازند. این آمادگی، تنها از رهگذر شناخت تجربهٔ همسایگان در مسیر توسعه و نیز تجربهٔ تاریخی ایران در دوران پهلوی ممکن است.</AP>
      <AP>باید همواره به یاد داشت که فرهنگ و هنر در ایران نه «هزینه»، بلکه «سرمایه»ای ارزشمند است. نادیده‌گرفتن این واقعیت، در عمل باعث شده هنر ایران، با همهٔ ظرفیت تاریخی و خلاقانه‌اش، یا در بازار داخلی محدود بماند یا در صحنهٔ منطقه‌ای و جهانی میدان را به دیگران واگذار کند؛ در حالی که بسیاری از کشورها سال‌هاست دریافته‌اند فرهنگ و هنر، اگر با نگاهی اقتصادی و ملی دیده شوند، می‌توانند هم موتور رشد اقتصادی باشند و هم ابزار قدرت نرم و سیاسی.</AP>
      <AP>فرهنگ و هنر منطق سرمایه‌گذاری خاص خود را دارند و نمی‌توان آن‌ها را با معیارهای پروژه‌های عمرانی یا صنعتی سنجید. بازدهی این حوزه ترکیبی است از سود اقتصادی، اعتبار بین‌المللی، گردشگری، صادرات فرهنگی و اثرات اجتماعی بلندمدت. تخصیص بخشی از سرمایهٔ یک صندوق سرمایه‌گذاری دولتی به فرهنگ و هنر می‌تواند از تولید حرفه‌ای هنر داخلی با ابزارهای انگیزشی شفاف حمایت کند—نه از طریق یارانه‌های پراکنده، بلکه با سرمایه‌گذاری هدفمند؛ فرصت و چارچوب‌های لازم برای ورود سرمایهٔ خارجی و مشارکت بخش خصوصی داخلی را فراهم آورد؛ و زیرساخت‌های حضور جهانی هنر ایران را ایجاد کند؛ امری که خود نیازمند سیاست خارجی همسو با منافع ایران به‌مثابه یک دولت–ملت است.</AP>
      <AP>تحقق هم‌زمان این اقدامات می‌تواند ایران را بار دیگر به بازیگری جدی در بازار هنر و گردشگری فرهنگی خاورمیانه و جهان بدل کند و منافعی گسترده برای حوزه‌های اقتصادی و سیاسی کشور به همراه آورد. تجربهٔ تاریخی ایران در دوران پهلوی و تجربهٔ معاصر همسایگان‌مان، هر دو پیامی روشن دارند: بدون یک صندوق حرفه‌ای، مستقل و آینده‌نگر، این فرصت دوباره از دست خواهد رفت.</AP>

      <AH>سخن پایانی</AH>
      <p className="essay-close">می‌توان گفت آنچه امروز در خاورمیانه در جریان است، نشانهٔ گذار فرهنگ و هنر از حاشیه سیاست به متن رقابت ملی و منطقه‌ای است. کشورهایی که این واقعیت را زودتر درک کرده‌اند، با اتکا به صندوق‌های سرمایه‌گذاری دولتی و نهادهای حرفه‌ای، فرهنگ را به دارایی راهبردی، ابزار قدرت نرم و موتور توسعه اقتصادی بدل کرده‌اند. ایران، با وجود سرمایهٔ تاریخی و فرهنگی کم‌نظیر، به‌دلیل فقدان چنین سازوکاری و نبود یک دولت ملی از این رقابت عقب مانده است. ایجاد یک صندوق سرمایه‌گذاری ملی و نگاه ویژه به سرمایه‌گذاری در بخش فرهنگ و هنر—مستقل، شفاف و آینده‌نگر—نه یک انتخاب لوکس، بلکه ضرورتی برای بازسازی جایگاه ایران در عرصهٔ منطقه‌ای و جهانی است؛ ضرورتی که اگر امروز از سوی میهن‌دوستان به آن اندیشیده نشود، حتی در فردای آزادی ایران و روی کارآمدن دولتی ملی نیز این فرصت بیش از پیش مسکوت خواهد ماند و ایران از رقابت‌های منطقه‌ای عقب خواهد ماند.</p>

      <ArtFnList notes={OIL_NOTES} />
    </React.Fragment>
  );
}

